+}
+
+template <>
+inline Optional<int> Attribute::as<int>() const {
+  return asInt();
+}
+
+template <>
+inline Optional<int> Attribute::as<Optional<int>>() const {
+  return asInt();
+}
+
+template <>
+inline Optional<bool> Attribute::as<bool>() const {
