+  return utils::anyOf(outer,
+                      [ p1 = prev.leftBound().back(), p2 = prev.rightBound().back() ](const ConstLineString3d& ls) {
+                        return (ls.front() == p1 && ls.back() == p2) || (ls.front() == p2 && ls.back() == p1);
