+template <typename Lanelet1T, typename Lanelet2T>
+IfLL<Lanelet1T, bool> intersects3d(const Lanelet1T& lanelet, const Lanelet2T& otherLanelet, double heightTolerance) {
+  if (intersects2d(lanelet, otherLanelet)) {
