+  auto line = lanelet.leftBound();
+  auto step = std::max(1ul, line.size() / 10);
+  for (auto i1 = 0ul, i2 = step; i2 < line.size(); i1 += step, i2 += step) {
+    length += distance2d(line[i1], line[i2]);
