+  void reserve(size_t num) { points().reserve(num); }
+
+  //! Changes the number of points contained either by deleting them or by
+  //! inserting new (invalId points).
+  void resize(size_t num) {
+    if (inverted()) {
+      std::reverse(begin(), end());
