+  });
+  using RetT = typename decltype(f(*c.begin()).first)::value_type;
+  std::vector<RetT> ret;
+  ret.reserve(size);
+  MoveIf<std::is_rvalue_reference<decltype(c)>::value> move;
+  for (auto& elem : c) {
