+Optional<int> Attribute::asInt() const {
+  // try load from cache
+  auto val = load<int>(cache_);
+  if (val != nullptr) {
+    return *val;
+  }
+  // need to compute value
+  try {
+    return store(cache_, boost::lexical_cast<int>(value()));
+  } catch (boost::bad_lexical_cast&) {
+    return {};
+  }
