+template <typename T>
+T writeAndLoad(const T& t) {
+  std::stringstream ss;
+  boost::archive::binary_oarchive oa(ss);
+  oa << t;
+  T tout;
+  boost::archive::binary_iarchive ia(ss);
+  ia >> tout;
+  return tout;
+}
